/**
 * Role & Permission Constants
 *
 * Single source of truth for the RBAC system. Every protected admin page
 * must have an entry in MODULES. Roles define default permissions but can
 * be overridden per-user via the `permissions` field in their user doc.
 */

// ============================================
// MODULES — one key per protected admin page
// ============================================
export const MODULES = {
  dashboard:    { key: 'dashboard',    label: 'Dashboard',      path: '/admin' },
  orders:       { key: 'orders',       label: 'Órdenes',        path: '/admin/ordenes' },
  acquisitions: { key: 'acquisitions', label: 'Adquisiciones',  path: '/admin/adquisiciones' },
  brokerage:    { key: 'brokerage',    label: 'Encargos',       path: '/admin/encargos' },
  inventory:    { key: 'inventory',    label: 'Inventario',     path: '/admin/inventario' },
  clients:      { key: 'clients',      label: 'Clientes',       path: '/admin/clientes' },
  marketing:    { key: 'marketing',    label: 'Marketing',      path: '/admin/marketing' },
  collection:   { key: 'collection',   label: 'Mi Colección',   path: '/admin/coleccion' },
  scouting:     { key: 'scouting',     label: 'Scouting',       path: '/admin/scouting' },
  box_breaks:   { key: 'box_breaks',   label: 'Aperturas',      path: '/admin/aperturas' },
  grading:      { key: 'grading',      label: 'Grading',        path: '/admin/grading' },
}

export const ALL_MODULE_KEYS = Object.keys(MODULES)

// Priority order for post-login landing and RoleGuard fallback.
// First accessible module wins.
export const DEFAULT_LANDING_ORDER = [
  'dashboard', 'orders', 'inventory', 'clients',
  'acquisitions', 'brokerage', 'marketing',
]

/**
 * Returns the first module path the user can access.
 */
export const resolveFirstAccessiblePath = (canAccessModule) => {
  for (const key of DEFAULT_LANDING_ORDER) {
    if (canAccessModule(key)) return MODULES[key]?.path || null
  }
  return null
}

// ============================================
// OWNER ROLE — hardcoded system superuser
// ============================================
// Cannot be edited or deleted. Prevents lockout.
export const OWNER_ROLE = {
  key: 'owner',
  label: 'Propietario',
  description: 'Acceso completo al sistema incluyendo gestión de usuarios y roles.',
  permissions: ALL_MODULE_KEYS,
  isSystem: true,
  isOwner: true,
}

// ============================================
// DEFAULT ROLES — seeded into Firestore on first run
// ============================================
// After seeding, these live in the `roles` collection and can be edited
// from the Settings page. System roles can't be deleted but their
// permissions and labels can be modified.
export const DEFAULT_ROLES = [
  {
    key: 'admin',
    label: 'Administrador',
    description: 'Acceso a todas las páginas operativas. No puede gestionar usuarios ni roles.',
    permissions: ALL_MODULE_KEYS,
    isSystem: true,
  },
  {
    key: 'manager',
    label: 'Gerente',
    description: 'Acceso a operaciones principales: órdenes, inventario, clientes y marketing.',
    permissions: [
      'dashboard', 'orders', 'acquisitions', 'brokerage',
      'inventory', 'clients', 'marketing',
    ],
    isSystem: true,
  },
  {
    key: 'employee',
    label: 'Empleado',
    description: 'Acceso básico a órdenes e inventario.',
    permissions: ['dashboard', 'orders', 'inventory'],
    isSystem: true,
  },
  {
    key: 'viewer',
    label: 'Visualizador',
    description: 'Acceso de solo lectura al dashboard y órdenes.',
    permissions: ['dashboard', 'orders'],
    isSystem: true,
  },
]

// ============================================
// HELPERS
// ============================================

/**
 * Build a Map<roleKey, roleDoc> from Firestore role docs,
 * always including the hardcoded owner role.
 */
export const buildRolesMap = (firestoreRoles = []) => {
  const map = new Map()
  map.set(OWNER_ROLE.key, OWNER_ROLE)
  firestoreRoles.forEach((r) => {
    if (r?.key) map.set(r.key, r)
  })
  return map
}

/**
 * Resolve the effective permission list for a user doc.
 * - Owner always has everything
 * - If user has a per-user `permissions` override (non-empty), use that
 * - Otherwise fall back to the role's permissions from the map
 */
export const getEffectivePermissions = (userDoc, rolesMap) => {
  if (!userDoc) return []
  if (userDoc.role === 'owner') return ALL_MODULE_KEYS
  if (Array.isArray(userDoc.permissions) && userDoc.permissions.length > 0) {
    return userDoc.permissions
  }
  if (rolesMap) {
    const role = rolesMap.get(userDoc.role)
    if (role) return role.permissions || []
  }
  const fallback = DEFAULT_ROLES.find((r) => r.key === userDoc.role)
  return fallback?.permissions || []
}

/**
 * Check if a user can access a specific module.
 */
export const canAccessModule = (userDoc, moduleKey, rolesMap) => {
  if (!userDoc) return false
  if (userDoc.status === 'inactive') return false
  if (userDoc.role === 'owner') return true
  if (moduleKey === 'configuracion') return false
  return getEffectivePermissions(userDoc, rolesMap).includes(moduleKey)
}

/**
 * Check if a user is the owner.
 */
export const isOwner = (userDoc) =>
  userDoc?.role === 'owner' && userDoc?.status !== 'inactive'

/**
 * Check if a user is an admin (owner or admin role).
 */
export const isAdminOrOwner = (userDoc) =>
  userDoc?.status !== 'inactive' && (userDoc?.role === 'owner' || userDoc?.role === 'admin')

