/**
 * UserService
 *
 * CRUD for the `admin_users` collection (user profiles with role + permissions)
 * and Firebase Auth user creation.
 *
 * User creation uses a SECONDARY Firebase app so the current admin session
 * is never disrupted by createUserWithEmailAndPassword.
 */

import {
  collection,
  doc,
  getDoc,
  getDocs,
  setDoc,
  updateDoc,
  deleteDoc,
  query,
  orderBy,
  serverTimestamp,
} from 'firebase/firestore'
import {
  createUserWithEmailAndPassword,
  getAuth,
  signOut as secondarySignOut,
  updateProfile,
} from 'firebase/auth'
import { initializeApp, getApps, getApp, deleteApp } from 'firebase/app'
import { db, firebaseConfig } from './firebaseConfig'

const USERS_COL = 'admin_users'
const SECONDARY_APP_NAME = 'user-creation-worker'

/**
 * Get or create a secondary Firebase app for user creation.
 */
const getSecondaryAuth = () => {
  const existing = getApps().find((a) => a.name === SECONDARY_APP_NAME)
  const secondaryApp = existing || initializeApp(firebaseConfig, SECONDARY_APP_NAME)
  return getAuth(secondaryApp)
}

const cleanupSecondaryApp = async () => {
  try {
    const app = getApp(SECONDARY_APP_NAME)
    if (app) await deleteApp(app)
  } catch {
    // App doesn't exist — fine
  }
}

const mapAuthError = (err) => {
  const code = err?.code || ''
  if (code === 'auth/email-already-in-use') {
    return new Error('Ya existe un usuario con este correo electrónico')
  }
  if (code === 'auth/invalid-email') {
    return new Error('Formato de correo electrónico inválido')
  }
  if (code === 'auth/weak-password') {
    return new Error('La contraseña es muy débil (mínimo 6 caracteres)')
  }
  if (code === 'auth/operation-not-allowed') {
    return new Error('La autenticación por correo/contraseña no está habilitada')
  }
  return new Error(err.message || 'Error creando el usuario')
}

// ============================================
// READ
// ============================================

export const fetchAllUsers = async () => {
  const q = query(collection(db, USERS_COL), orderBy('createdAt', 'desc'))
  const snap = await getDocs(q)
  return snap.docs.map((d) => ({ id: d.id, ...d.data() }))
}

export const fetchUser = async (uid) => {
  const snap = await getDoc(doc(db, USERS_COL, uid))
  return snap.exists() ? { id: snap.id, ...snap.data() } : null
}

// ============================================
// CREATE
// ============================================

/**
 * Create a new user in Firebase Auth (secondary app) + Firestore profile.
 *
 * @param {Object} payload - { email, password, fullName, role, permissions?, createdBy }
 */
export const createUser = async (payload) => {
  const { email, password, fullName, role, permissions = [], createdBy = '' } = payload

  if (!email || !password || !fullName || !role) {
    throw new Error('Email, contraseña, nombre y rol son requeridos')
  }
  if (password.length < 6) {
    throw new Error('La contraseña debe tener al menos 6 caracteres')
  }
  if (role === 'owner') {
    throw new Error('No se puede crear un usuario con rol de propietario')
  }

  const secondaryAuth = getSecondaryAuth()
  let newUid
  try {
    const cred = await createUserWithEmailAndPassword(secondaryAuth, email, password)
    newUid = cred.user.uid

    try {
      await updateProfile(cred.user, { displayName: fullName })
    } catch {
      // non-fatal
    }

    await secondarySignOut(secondaryAuth).catch(() => {})
  } catch (err) {
    await cleanupSecondaryApp().catch(() => {})
    throw mapAuthError(err)
  }

  const profile = {
    uid: newUid,
    email,
    fullName,
    role,
    permissions,
    status: 'active',
    needsPasswordChange: true,
    lastLogin: null,
    createdAt: serverTimestamp(),
    createdBy,
    updatedAt: serverTimestamp(),
  }

  try {
    await setDoc(doc(db, USERS_COL, newUid), profile)
  } catch (err) {
    console.error('Failed to write user profile after auth create:', err)
    throw new Error('Usuario de Auth creado pero falló el guardado del perfil: ' + err.message)
  }

  await cleanupSecondaryApp().catch(() => {})

  return { id: newUid, ...profile }
}

// ============================================
// UPDATE
// ============================================

/**
 * Update a user profile's mutable fields. Owner-only operation.
 */
export const updateUser = async (uid, updates) => {
  const allowed = {}
  if (updates.fullName !== undefined) allowed.fullName = updates.fullName
  if (updates.role !== undefined) allowed.role = updates.role
  if (updates.permissions !== undefined) allowed.permissions = updates.permissions
  if (updates.status !== undefined) allowed.status = updates.status
  if (updates.needsPasswordChange !== undefined) allowed.needsPasswordChange = updates.needsPasswordChange

  allowed.updatedAt = serverTimestamp()

  await updateDoc(doc(db, USERS_COL, uid), allowed)
  return fetchUser(uid)
}

/**
 * Update only the current user's own profile (fullName).
 */
export const updateOwnProfile = async (uid, { fullName }) => {
  const updates = { updatedAt: serverTimestamp() }
  if (fullName !== undefined) updates.fullName = fullName
  await updateDoc(doc(db, USERS_COL, uid), updates)
  return fetchUser(uid)
}

/**
 * Record last login timestamp.
 */
export const recordLogin = async (uid) => {
  try {
    await updateDoc(doc(db, USERS_COL, uid), {
      lastLogin: serverTimestamp(),
    })
  } catch {
    // non-fatal
  }
}

// ============================================
// STATUS
// ============================================

export const deactivateUser = async (uid) => {
  await updateDoc(doc(db, USERS_COL, uid), {
    status: 'inactive',
    updatedAt: serverTimestamp(),
  })
}

export const activateUser = async (uid) => {
  await updateDoc(doc(db, USERS_COL, uid), {
    status: 'active',
    updatedAt: serverTimestamp(),
  })
}

// ============================================
// DELETE
// ============================================

/**
 * Delete a user profile from Firestore.
 * NOTE: Does NOT delete the Firebase Auth user (requires Admin SDK).
 * Setting status to 'inactive' is preferred.
 */
export const deleteUserProfile = async (uid) => {
  await deleteDoc(doc(db, USERS_COL, uid))
}

