/**
 * RoleService
 *
 * CRUD for the `roles` collection. Roles define named bundles of module
 * permissions that can be assigned to users.
 *
 * The owner role is NOT stored in Firestore — it's hardcoded in
 * constants/roles.js. All other roles (admin, manager, employee, viewer)
 * live in this collection and can be edited by the owner.
 */

import {
  collection,
  doc,
  getDocs,
  getDoc,
  setDoc,
  updateDoc,
  deleteDoc,
  query,
  where,
  orderBy,
  serverTimestamp,
  limit,
