// SEED — bootstrap default roles if collection is empty
// ============================================

/**
 * If the `roles` collection is empty, write the default roles.
 * Safe to call multiple times — no-op if any roles exist.
 */
export const seedDefaultRolesIfEmpty = async () => {
  try {
    const q = query(collection(db, ROLES_COL), limit(1))
    const snap = await getDocs(q)
    if (!snap.empty) return false

    for (const role of DEFAULT_ROLES) {
      const ref = doc(collection(db, ROLES_COL), role.key)
      await setDoc(ref, {
        key: role.key,
        label: role.label,
        description: role.description,
        permissions: role.permissions,
        isSystem: role.isSystem || false,
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
      })
    }
    return true
  } catch (err) {
    console.warn('seedDefaultRolesIfEmpty failed:', err)
    return false
  }
