// ============================================
// CREATE
// ============================================

/**
 * Create a new custom role.
 */
export const createRole = async (payload) => {
  const { key, label, description = '', permissions = [] } = payload

  if (!key || !label) {
    throw new Error('Clave y nombre son requeridos')
  }
  if (key === 'owner') {
    throw new Error('No se puede crear un rol llamado "owner"')
  }
  if (!/^[a-z0-9_-]+$/i.test(key)) {
    throw new Error('La clave solo puede contener letras, números, guiones y guiones bajos')
  }

  const invalidPerms = permissions.filter((p) => !ALL_MODULE_KEYS.includes(p))
  if (invalidPerms.length > 0) {
    throw new Error(`Permisos inválidos: ${invalidPerms.join(', ')}`)
  }

  const existing = await getDoc(doc(db, ROLES_COL, key))
  if (existing.exists()) {
    throw new Error(`Ya existe un rol con la clave "${key}"`)
  }

  const ref = doc(collection(db, ROLES_COL), key)
  const data = {
    key,
    label,
    description,
    permissions,
    isSystem: false,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
  }
  await setDoc(ref, data)

  return { id: key, ...data }
