 * Update a role's label, description, or permissions.
 * System roles can have their permissions edited but not their key.
 */
export const updateRole = async (id, updates) => {
  if (id === 'owner') {
    throw new Error('El rol de propietario no se puede editar')
  }

  const allowed = {}
  if (updates.label !== undefined) allowed.label = updates.label
  if (updates.description !== undefined) allowed.description = updates.description
  if (updates.permissions !== undefined) {
    const invalid = updates.permissions.filter((p) => !ALL_MODULE_KEYS.includes(p))
    if (invalid.length > 0) {
      throw new Error(`Permisos inválidos: ${invalid.join(', ')}`)
    }
    allowed.permissions = updates.permissions
  }
  allowed.updatedAt = serverTimestamp()

  await updateDoc(doc(db, ROLES_COL, id), allowed)
  return fetchRole(id)
}

// ============================================
// DELETE
// ============================================

/**
 * Delete a role. System roles cannot be deleted. Custom roles can only
 * be deleted if no users are assigned to them.
 */
export const deleteRole = async (id) => {
  if (id === 'owner') {
    throw new Error('El rol de propietario no se puede eliminar')
  }

  const roleSnap = await getDoc(doc(db, ROLES_COL, id))
  if (!roleSnap.exists()) {
    throw new Error('Rol no encontrado')
  }
  if (roleSnap.data().isSystem) {
    throw new Error('Los roles del sistema no se pueden eliminar')
  }

  const usersQ = query(collection(db, USERS_COL), where('role', '==', id))
  const usersSnap = await getDocs(usersQ)
  if (!usersSnap.empty) {
    throw new Error(
      `No se puede eliminar: ${usersSnap.size} usuario${usersSnap.size !== 1 ? 's' : ''} asignado${usersSnap.size !== 1 ? 's' : ''}. Reasigna primero.`
    )
  }

  await deleteDoc(doc(db, ROLES_COL, id))
