import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react'
import {
  onAuthStateChanged,
  signInWithEmailAndPassword,
  signOut,
} from 'firebase/auth'
import {
  collection,
  doc,
  getDoc,
  onSnapshot,
  orderBy,
  query,
  serverTimestamp,
  setDoc,
} from 'firebase/firestore'
import { auth, db } from '../services/firebaseConfig'
import {
  canAccessModule as canAccess,
  getEffectivePermissions,
  isOwner as checkIsOwner,
  isAdminOrOwner as checkIsAdminOrOwner,
  buildRolesMap,
  OWNER_ROLE,
} from '../constants/roles'
import { seedDefaultRolesIfEmpty } from '../services/RoleService'
import { recordLogin } from '../services/UserService'

const AuthContext = createContext(null)

/**
 * AuthContext
 *
 * Exposes:
 * - currentUser: Firebase Auth user object (or null)
 * - userProfile: Firestore admin_users doc with role/permissions (or null)
 * - roles: array of role docs from Firestore
 * - rolesMap: Map<key, roleDoc> including the hardcoded owner role
 * - loading: true while auth + profile + roles are resolving
 * - isOwner: shortcut for userProfile.role === 'owner'
 * - isAdminOrOwner: owner or admin role
 * - canAccessModule(moduleKey): permission check
 * - permissions: effective permission list for the current user
 * - login / logout
 * - refreshUserProfile
 *
 * Bootstrap: the FIRST user to log in is auto-promoted to owner if no
 * admin_users doc exists for them yet.
 */
export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(undefined)
  const [userProfile, setUserProfile] = useState(null)
  const [roles, setRoles] = useState([])
  const [profileLoading, setProfileLoading] = useState(true)
  const [rolesLoading, setRolesLoading] = useState(true)

  const loading = profileLoading || rolesLoading

  // Listen to Firebase Auth state
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      setCurrentUser(user)
      if (!user) {
        setUserProfile(null)
        setProfileLoading(false)
        setRolesLoading(false)
      } else {
        setProfileLoading(true)
        setRolesLoading(true)
      }
    })
    return unsubscribe
  }, [])

  // Subscribe to the user's Firestore profile doc
  useEffect(() => {
    if (!currentUser) return undefined

    let unsub
    const ref = doc(db, 'admin_users', currentUser.uid)

    const bootstrapIfNeeded = async () => {
      const snap = await getDoc(ref)
      if (snap.exists()) return

      // No profile doc — bootstrap this user as owner
      try {
        await setDoc(ref, {
          uid: currentUser.uid,
          email: currentUser.email || '',
          fullName: currentUser.displayName || currentUser.email?.split('@')[0] || 'Owner',
          role: 'owner',
          permissions: [],
          status: 'active',
          needsPasswordChange: false,
          lastLogin: serverTimestamp(),
          createdAt: serverTimestamp(),
          createdBy: 'self-bootstrap',
          updatedAt: serverTimestamp(),
        })
      } catch (err) {
        console.warn('Could not bootstrap user profile:', err.message)
      }
    }

    ;(async () => {
      await bootstrapIfNeeded()

      unsub = onSnapshot(
        ref,
        (snap) => {
          if (snap.exists()) {
            const profile = { id: snap.id, ...snap.data() }
            setUserProfile(profile)

            // Seed default roles once we have a confirmed owner/admin profile
            if (
              (profile.role === 'owner' || profile.role === 'admin') &&
              profile.status === 'active'
            ) {
              seedDefaultRolesIfEmpty().catch(() => {})
            }

            // Record login (fire-and-forget)
            recordLogin(currentUser.uid)
          } else {
            setUserProfile(null)
          }
          setProfileLoading(false)
        },
        (err) => {
          console.error('Error subscribing to user profile:', err)
          setUserProfile(null)
          setProfileLoading(false)
        }
      )
    })()

    return () => {
      if (unsub) unsub()
    }
  }, [currentUser])

  // Subscribe to the roles collection
  useEffect(() => {
    if (!currentUser) {
      setRoles([])
      setRolesLoading(false)
      return undefined
    }
    const q = query(collection(db, 'roles'), orderBy('createdAt', 'asc'))
    const unsub = onSnapshot(
      q,
      (snap) => {
        setRoles(snap.docs.map((d) => ({ id: d.id, ...d.data() })))
        setRolesLoading(false)
      },
      (err) => {
        console.error('Error subscribing to roles:', err)
        setRoles([])
        setRolesLoading(false)
      }
    )
    return unsub
  }, [currentUser])

  const login = (email, password) => {
    return signInWithEmailAndPassword(auth, email, password)
  }

  const logout = () => {
    return signOut(auth)
  }

  const refreshUserProfile = useCallback(async () => {
    if (!currentUser) return
    try {
      const snap = await getDoc(doc(db, 'admin_users', currentUser.uid))
      if (snap.exists()) setUserProfile({ id: snap.id, ...snap.data() })
    } catch (err) {
      console.error('Error refreshing user profile:', err)
    }
  }, [currentUser])

  const rolesMap = useMemo(() => buildRolesMap(roles), [roles])

  const canAccessModule = useCallback(
    (moduleKey) => canAccess(userProfile, moduleKey, rolesMap),
    [userProfile, rolesMap]
  )

  const value = useMemo(
    () => ({
      currentUser,
      userProfile,
      roles,
      rolesMap,
      ownerRole: OWNER_ROLE,
      loading,
      isOwner: checkIsOwner(userProfile),
      isAdminOrOwner: checkIsAdminOrOwner(userProfile),
      permissions: getEffectivePermissions(userProfile, rolesMap),
      canAccessModule,
      login,
      logout,
      refreshUserProfile,
    }),
    [currentUser, userProfile, roles, rolesMap, loading, canAccessModule, refreshUserProfile]
  )

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

export const useAuth = () => {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

