import { useAuth } from '../../contexts/AuthContext'
import { resolveFirstAccessiblePath } from '../../constants/roles'

const M = 'Montserrat, sans-serif'

/**
 * RoleGuard
 *
 * Protects routes by checking authenticated user's permissions.
 *
 * Usage:
 *   <Route element={<RoleGuard module="inventory" />}>
 *     <Route path="inventario" element={<AdminInventory />} />
 *   </Route>
 *
 *   <Route element={<RoleGuard ownerOnly />}>
 *     <Route path="configuracion" element={<AdminSettings />} />
 *   </Route>
 */
const RoleGuard = ({ module, ownerOnly = false }) => {
  const { currentUser, userProfile, isOwner, canAccessModule, loading } = useAuth()

  if (loading || userProfile === undefined) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center">
        <div className="flex items-center gap-2">
          <div
            className="w-2.5 h-2.5 rounded-full animate-bounce"
            style={{ background: 'var(--color-gold)', animationDelay: '0ms' }}
          />
          <div
            className="w-2.5 h-2.5 rounded-full animate-bounce"
            style={{ background: 'var(--color-gold)', animationDelay: '150ms' }}
          />
          <div
            className="w-2.5 h-2.5 rounded-full animate-bounce"
            style={{ background: 'var(--color-gold)', animationDelay: '300ms' }}
          />
        </div>
      </div>
    )
  }

  if (!currentUser) {
    return <Navigate to="/admin/login" replace />
  }

  if (!userProfile || userProfile.status === 'inactive') {
    return <AccessDeniedScreen reason="Tu cuenta está inactiva. Contacta al propietario." />
  }

  if (ownerOnly && !isOwner) {
    return <AccessDeniedScreen reason="Esta sección es solo para el propietario." />
  }

  if (module && !canAccessModule(module)) {
    const fallback = resolveFirstAccessiblePath(canAccessModule)
    if (fallback) return <Navigate to={fallback} replace />
    return <AccessDeniedScreen reason="Tu cuenta no tiene permisos asignados. Contacta al propietario." />
  }

  return <Outlet />
}

const AccessDeniedScreen = ({ reason }) => (
  <div className="min-h-[60vh] flex items-center justify-center px-6">
