import { useState, useEffect } from 'react'
import { Outlet, NavLink, Link, useNavigate, useLocation } from 'react-router-dom'
import {
  LayoutDashboard,
  ClipboardList,
  Inbox,
  Globe,
  Package,
  Users,
  Megaphone,
  Vault,
  Target,
  PackageOpen,
  Sparkles,
  LogOut,
  Store,
  Menu,
  X,
  ChevronLeft,
  ChevronRight,
  User,
} from 'lucide-react'
import { useAuth } from '../../contexts/AuthContext'
import ggIcon from '../../assets/images/gg_icon.png'

const sidebarLinks = [
  { to: '/admin', label: 'Dashboard', icon: LayoutDashboard, end: true },
  { to: '/admin/ordenes', label: 'Órdenes', icon: ClipboardList },
  { to: '/admin/adquisiciones', label: 'Adquisiciones', icon: Inbox },
  { to: '/admin/encargos', label: 'Encargos', icon: Globe },
  { to: '/admin/inventario', label: 'Inventario', icon: Package },
  { to: '/admin/clientes', label: 'Clientes', icon: Users },
  { to: '/admin/marketing', label: 'Marketing', icon: Megaphone },
  { to: '/admin/coleccion', label: 'Mi Colección', icon: Vault },
  { to: '/admin/scouting', label: 'Scouting', icon: Target },
  { to: '/admin/aperturas', label: 'Aperturas', icon: PackageOpen },
  { to: '/admin/grading', label: 'Grading', icon: Sparkles },
]

const pageTitles = {
  '/admin': 'Dashboard',
  '/admin/ordenes': 'Órdenes',
  '/admin/adquisiciones': 'Adquisiciones',
  '/admin/encargos': 'Encargos / Importaciones',
  '/admin/inventario': 'Inventario',
  '/admin/clientes': 'Clientes',
  '/admin/marketing': 'Marketing',
  '/admin/coleccion': 'Mi Colección',
  '/admin/scouting': 'Scouting Tool',
  '/admin/aperturas': 'Aperturas',
  '/admin/grading': 'Grading',
}

const AdminLayout = () => {
  const { currentUser, logout } = useAuth()
  const navigate = useNavigate()
  const location = useLocation()
  const [sidebarOpen, setSidebarOpen] = useState(false)
  const [collapsed, setCollapsed] = useState(false)

  // Toggle admin-mode class on body to kill storefront texture
  useEffect(() => {
    document.body.classList.add('admin-mode')
    return () => document.body.classList.remove('admin-mode')
  }, [])

  const handleLogout = async () => {
    await logout()
    navigate('/admin/login')
  }

  const currentTitle = pageTitles[location.pathname] || 'Admin'

  return (
    <div className="min-h-screen" style={{ background: '#0B1021' }}>
      {/* Mobile sidebar overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-black/60 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* ── Sidebar ── */}
      <aside
        className={`fixed top-0 left-0 z-50 h-full bg-[#050814] flex flex-col transition-all duration-300 ${
          sidebarOpen ? 'w-64 translate-x-0' : '-translate-x-full'
        } ${collapsed ? 'lg:w-20' : 'lg:w-64'} lg:translate-x-0`}
        style={{ borderRight: '1px solid rgba(212, 175, 55, 0.15)' }}
      >
        {/* Logo / Header */}
        <div
          className="flex items-center justify-between h-16 px-4"
          style={{ borderBottom: '1px solid rgba(212, 175, 55, 0.15)' }}
        >
          {!collapsed && (
            <Link to="/admin" className="flex items-center gap-2.5">
              <img src={ggIcon} alt="GG" className="w-8 h-8 rounded-lg object-contain" />
              <span
                className="text-gradient-gold text-base"
                style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 800, letterSpacing: '0.08em' }}
              >
                GRAND GAMING
              </span>
            </Link>
          )}
          {collapsed && (
            <div className="hidden lg:flex w-full justify-center">
              <img src={ggIcon} alt="GG" className="w-7 h-7 rounded-lg object-contain" />
            </div>
          )}
          <button
            onClick={() => {
              if (window.innerWidth < 1024) {
                setSidebarOpen(false)
              } else {
                setCollapsed(!collapsed)
              }
            }}
            className="hidden lg:flex p-1.5 rounded-lg text-[var(--color-text-muted)] hover:text-white hover:bg-white/5 transition-colors"
          >
            {collapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
          </button>
          <button
            onClick={() => setSidebarOpen(false)}
            className="lg:hidden p-1.5 text-[var(--color-text-muted)] hover:text-white transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 py-4 px-3 flex flex-col gap-1 overflow-y-auto">
          {sidebarLinks.map(({ to, label, icon: Icon, end }) => {
            const isActive = end
              ? location.pathname === to
              : location.pathname.startsWith(to)

            return (
              <NavLink
                key={to}
                to={to}
                end={end}
                onClick={() => setSidebarOpen(false)}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg no-underline transition-all duration-200 ${
                  isActive
                    ? 'bg-[var(--color-gold)]/10 text-[var(--color-gold)]'
                    : 'text-[var(--color-text-secondary)] hover:bg-white/5 hover:text-white'
                }`}
                style={isActive ? { borderLeft: '3px solid var(--color-gold)' } : { borderLeft: '3px solid transparent' }}
                title={collapsed ? label : undefined}
              >
                <Icon className="w-5 h-5 shrink-0" />
                {!collapsed && (
                  <span
                    className="text-sm"
                    style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: isActive ? 700 : 600 }}
                  >
                    {label}
                  </span>
                )}
              </NavLink>
            )
          })}
        </nav>

        {/* Bottom section */}
        <div className="p-3 flex flex-col gap-1" style={{ borderTop: '1px solid rgba(212, 175, 55, 0.15)' }}>
          <Link
            to="/"
            className={`flex items-center gap-3 px-3 py-2.5 rounded-lg no-underline text-[var(--color-text-secondary)] hover:bg-white/5 hover:text-white transition-all duration-200 ${
              collapsed ? 'justify-center' : ''
            }`}
            title={collapsed ? 'Ir a la Tienda' : undefined}
          >
            <Store className="w-5 h-5 shrink-0" />
            {!collapsed && (
              <span
                className="text-sm"
                style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 600 }}
              >
                Ir a la Tienda
              </span>
            )}
          </Link>
          <button
            onClick={handleLogout}
            className={`flex items-center gap-3 px-3 py-2.5 rounded-lg w-full text-[var(--color-status-red)] hover:bg-[var(--color-status-red)]/10 transition-all duration-200 bg-transparent border-none cursor-pointer ${
              collapsed ? 'justify-center' : ''
            }`}
          >
            <LogOut className="w-5 h-5 shrink-0" />
            {!collapsed && (
              <span
                className="text-sm"
                style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 600 }}
              >
                Cerrar Sesión
              </span>
            )}
          </button>
        </div>
      </aside>

      {/* ── Main content area ── */}
      <div
        className={`transition-all duration-300 ${
          collapsed ? 'lg:ml-20' : 'lg:ml-64'
        }`}
      >
        {/* Top bar */}
        <header
          className="sticky top-0 z-20 h-16 flex items-center justify-between px-4 md:px-6"
          style={{
            background: 'rgba(11, 16, 33, 0.95)',
            backdropFilter: 'blur(8px)',
            borderBottom: '1px solid rgba(212, 175, 55, 0.1)',
          }}
        >
          {/* Left — mobile menu + page title */}
          <div className="flex items-center gap-4">
            <button
              onClick={() => setSidebarOpen(true)}
              className="lg:hidden p-2 rounded-lg text-[var(--color-text-secondary)] hover:text-white hover:bg-white/5 transition-colors"
            >
              <Menu className="w-5 h-5" />
            </button>
            <h2
              className="text-white text-sm sm:text-lg"
              style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 700 }}
            >
              {currentTitle}
            </h2>
          </div>

          {/* Right — user info */}
          <div className="flex items-center gap-3">
            <div className="hidden sm:block text-right">
              <p
                className="text-white text-sm leading-tight"
                style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 600 }}
              >
                {currentUser?.email?.split('@')[0] || 'Admin'}
              </p>
              <p
                className="text-[var(--color-text-muted)] text-xs"
                style={{ fontFamily: 'Montserrat, sans-serif', fontWeight: 400 }}
              >
                Administrador
              </p>
            </div>
            <div className="w-9 h-9 rounded-full bg-[var(--color-gold)]/15 flex items-center justify-center">
              <User className="w-4.5 h-4.5 text-[var(--color-gold)]" />
            </div>
          </div>
        </header>

        {/* Page content */}
        <main className="p-4 md:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  )
}

export default AdminLayout

