import React, { useState, useEffect, useCallback, useMemo } from 'react';
import {
  Settings,
  User,
  Users,
  ShieldCheck,
  Plus,
  Pencil,
  Trash2,
  Check,
  X,
  Loader2,
  AlertCircle,
  Eye,
  EyeOff,
  Save,
  UserCheck,
  UserX,
  Lock,
  Wrench,
  CheckCircle2,
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import {
  fetchAllUsers,
  createUser,
  updateUser,
  updateOwnProfile,
  deactivateUser,
  activateUser,
  deleteUserProfile,
} from '../services/UserService';
import { createRole, updateRole, deleteRole } from '../services/RoleService';
import { reclassifyInvoicePaymentStatus } from '../services/FirebaseService';
import { usePrototype } from '../contexts/PrototypeContext';
import { MODULES, ALL_MODULE_KEYS, ADMIN_ROLE } from '../constants/roles';
import Modal from '../components/ui/Modal';

const font = { fontFamily: 'Montserrat, sans-serif' };

// ============================================
// MAIN PAGE
// ============================================

const Configuracion = () => {
  const { userProfile, isAdmin, rolesMap, roles, refreshUserProfile } = useAuth();
  const [tab, setTab] = useState('perfil');

  const tabs = useMemo(() => {
    const base = [{ key: 'perfil', label: 'Mi Perfil', icon: User }];
    if (isAdmin) {
      base.push({ key: 'usuarios', label: 'Usuarios', icon: Users });
      base.push({ key: 'permisos', label: 'Roles y Permisos', icon: ShieldCheck });
      base.push({ key: 'mantenimiento', label: 'Mantenimiento', icon: Wrench });
    }
    return base;
  }, [isAdmin]);

  return (
    <div className="space-y-6 animate-fade-up">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div
          className="w-10 h-10 rounded-xl flex items-center justify-center"
          style={{ background: 'linear-gradient(135deg, #1B5E20 0%, #00897B 100%)' }}
        >
          <Settings className="w-5 h-5 text-white" strokeWidth={2} />
        </div>
        <div>
          <h2 className="text-xl text-text-primary" style={{ ...font, fontWeight: 700 }}>
            Configuración
          </h2>
          <p className="text-[11px] text-text-muted" style={{ ...font, fontWeight: 400 }}>
            {isAdmin ? 'Administra tu perfil, usuarios y permisos del sistema' : 'Administra tu perfil personal'}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 rounded-lg p-0.5" style={{ backgroundColor: '#f1f5f9', border: '1px solid #e2e8f0', width: 'fit-content' }}>

