import React, { useState, useEffect, useCallback, useMemo } from 'react'
import {
  Settings as SettingsIcon,
  User,
  Users,
  ShieldCheck,
  Plus,
  Pencil,
  Trash2,
  Check,
  X,
  Loader2,
  AlertCircle,
  Eye,
  EyeOff,
  Save,
  UserCheck,
  UserX,
} from 'lucide-react'
import { useAuth } from '../../contexts/AuthContext'
import {
  fetchAllUsers,
  createUser,
  updateUser,
  updateOwnProfile,
  deactivateUser,
  activateUser,
  deleteUserProfile,
} from '../../services/UserService'
import { createRole, updateRole, deleteRole } from '../../services/RoleService'
import { MODULES, ALL_MODULE_KEYS, OWNER_ROLE } from '../../constants/roles'

const M = 'Montserrat, sans-serif'

// ============================================
// MAIN PAGE
// ============================================

const Settings = () => {
  const { userProfile, isOwner, rolesMap, roles, refreshUserProfile } = useAuth()
  const [tab, setTab] = useState('perfil')

  const tabs = useMemo(() => {
    const base = [{ key: 'perfil', label: 'Mi Perfil', icon: User }]
    if (isOwner) {
      base.push({ key: 'usuarios', label: 'Usuarios', icon: Users })
      base.push({ key: 'permisos', label: 'Roles y Permisos', icon: ShieldCheck })
    }
    return base
  }, [isOwner])

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div
          className="w-10 h-10 rounded-xl flex items-center justify-center"
          style={{ background: 'linear-gradient(135deg, var(--color-gold-dark) 0%, var(--color-gold) 100%)' }}
        >
          <SettingsIcon className="w-5 h-5 text-[#0A1128]" strokeWidth={2} />
        </div>
        <div>
          <h2 className="text-white text-xl" style={{ fontFamily: M, fontWeight: 700 }}>
            Configuración
          </h2>
          <p className="text-[var(--color-text-muted)] text-[11px]" style={{ fontFamily: M, fontWeight: 400 }}>
            {isOwner ? 'Administra tu perfil, usuarios y permisos del sistema' : 'Administra tu perfil personal'}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div
        className="flex items-center gap-1 rounded-lg p-0.5"
        style={{ backgroundColor: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', width: 'fit-content' }}
      >
        {tabs.map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs transition-all"
            style={{
              fontFamily: M,
              fontWeight: tab === key ? 700 : 500,
              background: tab === key ? 'var(--color-gold)' : 'transparent',
              color: tab === key ? '#0A1128' : 'var(--color-text-secondary)',
              border: 'none',
              cursor: 'pointer',
            }}
          >
            <Icon className="w-3.5 h-3.5" />
            {label}
          </button>
        ))}
      </div>

      {/* Tab content */}
      {tab === 'perfil' && (
        <ProfileTab userProfile={userProfile} refreshUserProfile={refreshUserProfile} />
      )}
      {tab === 'usuarios' && isOwner && (
        <UsersTab rolesMap={rolesMap} roles={roles} currentUid={userProfile?.id} />
      )}
      {tab === 'permisos' && isOwner && (
        <RolesTab rolesMap={rolesMap} roles={roles} />
      )}
    </div>
  )
}

// ============================================
// PROFILE TAB
// ============================================

const ProfileTab = ({ userProfile, refreshUserProfile }) => {
  const [fullName, setFullName] = useState(userProfile?.fullName || '')
  const [saving, setSaving] = useState(false)
  const [saved, setSaved] = useState(false)

  useEffect(() => {
    if (userProfile?.fullName) setFullName(userProfile.fullName)
  }, [userProfile?.fullName])

  const handleSave = async () => {
    if (!fullName.trim() || fullName === userProfile?.fullName) return
    setSaving(true)
    try {
      await updateOwnProfile(userProfile.id, { fullName: fullName.trim() })
      await refreshUserProfile()
      setSaved(true)
      setTimeout(() => setSaved(false), 2000)
    } catch (err) {
      alert('Error: ' + err.message)
    } finally {
      setSaving(false)
    }
  }

  const roleLabel = userProfile?.role === 'owner' ? 'Propietario' : userProfile?.role || '—'

  return (
    <div className="card-navy rounded-2xl p-6 max-w-lg space-y-5">
      <h3 className="text-white text-sm" style={{ fontFamily: M, fontWeight: 700 }}>
        Información Personal
      </h3>

      {/* Email — read only */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Correo electrónico
        </label>
        <div
          className="px-3 py-2 rounded-lg text-sm text-[var(--color-text-muted)]"
          style={{ fontFamily: M, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.06)' }}
        >
          {userProfile?.email || '—'}
        </div>
      </div>

      {/* Role — read only */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Rol
        </label>
        <div
          className="px-3 py-2 rounded-lg text-sm"
          style={{
            fontFamily: M,
            fontWeight: 600,
            background: 'rgba(212, 175, 55, 0.08)',
            border: '1px solid rgba(212, 175, 55, 0.15)',
            color: 'var(--color-gold)',
          }}
        >
          {roleLabel}
        </div>
      </div>

      {/* Full name — editable */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Nombre completo
        </label>
        <input
          type="text"
          value={fullName}
          onChange={(e) => setFullName(e.target.value)}
          className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
          style={{
            fontFamily: M,
            background: 'rgba(255,255,255,0.06)',
            border: '1px solid rgba(255,255,255,0.1)',
          }}
        />
      </div>

      <button
        onClick={handleSave}
        disabled={saving || !fullName.trim() || fullName === userProfile?.fullName}
        className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs transition-all disabled:opacity-40"
        style={{
          fontFamily: M,
          fontWeight: 600,
          background: saved ? 'var(--color-status-green)' : 'var(--color-gold)',
          color: '#0A1128',
          border: 'none',
          cursor: saving ? 'wait' : 'pointer',
        }}
      >
        {saving ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : saved ? <Check className="w-3.5 h-3.5" /> : <Save className="w-3.5 h-3.5" />}
        {saving ? 'Guardando...' : saved ? 'Guardado' : 'Guardar Cambios'}
      </button>
    </div>
  )
}

// ============================================
// USERS TAB
// ============================================

const UsersTab = ({ rolesMap, roles, currentUid }) => {
  const [users, setUsers] = useState([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [editUser, setEditUser] = useState(null)
  const [error, setError] = useState('')

  const loadUsers = useCallback(async () => {
    try {
      const data = await fetchAllUsers()
      setUsers(data)
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => { loadUsers() }, [loadUsers])

  const handleToggleStatus = async (user) => {
    try {
      if (user.status === 'active') {
        await deactivateUser(user.id)
      } else {
        await activateUser(user.id)
      }
      await loadUsers()
    } catch (err) {
      setError(err.message)
    }
  }

  const handleDelete = async (user) => {
    if (!confirm(`¿Eliminar el perfil de ${user.fullName}? Esta acción no se puede deshacer.`)) return
    try {
      await deleteUserProfile(user.id)
      await loadUsers()
    } catch (err) {
      setError(err.message)
    }
  }

  // Available roles for assignment (exclude owner — owner is hardcoded)
  const assignableRoles = useMemo(() => {
    return [OWNER_ROLE, ...roles]
  }, [roles])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="w-6 h-6 text-[var(--color-gold)] animate-spin" />
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Error banner */}
      {error && (
        <div
          className="flex items-center gap-2 px-4 py-3 rounded-lg text-xs"
          style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
        >
          <AlertCircle className="w-4 h-4 shrink-0" />
          {error}
          <button onClick={() => setError('')} className="ml-auto p-0 bg-transparent border-none text-inherit cursor-pointer">
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      )}

      {/* Add user button */}
      <div className="flex justify-end">
        <button
          onClick={() => { setEditUser(null); setShowForm(true) }}
          className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold"
          style={{ fontFamily: M, fontWeight: 600 }}
        >
          <Plus className="w-4 h-4" />
          Agregar Usuario
        </button>
      </div>

      {/* Users list */}
      <div className="space-y-3">
        {users.map((user) => {
          const roleDef = rolesMap.get(user.role)
          const isCurrentUser = user.id === currentUid
          const isOwnerUser = user.role === 'owner'

          return (
            <div
              key={user.id}
              className="card-navy rounded-xl p-4 flex flex-col sm:flex-row sm:items-center gap-3"
            >
              {/* Avatar + info */}
              <div className="flex items-center gap-3 flex-1 min-w-0">
                <div
                  className="w-10 h-10 rounded-full flex items-center justify-center shrink-0 text-sm"
                  style={{
                    fontFamily: M,
                    fontWeight: 700,
                    background: user.status === 'inactive'
                      ? 'rgba(255,255,255,0.05)'
                      : isOwnerUser
                        ? 'rgba(212,175,55,0.15)'
                        : 'rgba(126,184,224,0.15)',
                    color: user.status === 'inactive'
                      ? 'var(--color-text-muted)'
                      : isOwnerUser
                        ? 'var(--color-gold)'
                        : 'var(--color-ice)',
                  }}
                >
                  {user.fullName?.charAt(0)?.toUpperCase() || '?'}
                </div>
                <div className="min-w-0">
                  <p className="text-white text-sm truncate" style={{ fontFamily: M, fontWeight: 600 }}>
                    {user.fullName}
                    {isCurrentUser && (
                      <span className="text-[var(--color-text-muted)] text-[10px] ml-2" style={{ fontWeight: 400 }}>(tú)</span>
                    )}
                  </p>
                  <p className="text-[var(--color-text-muted)] text-xs truncate" style={{ fontFamily: M }}>
                    {user.email}
                  </p>
                </div>
              </div>

              {/* Role badge */}
              <div className="flex items-center gap-2">
                <span
                  className="px-2.5 py-1 rounded-md text-[10px]"
                  style={{
                    fontFamily: M,
                    fontWeight: 700,
                    background: isOwnerUser ? 'rgba(212,175,55,0.12)' : 'rgba(126,184,224,0.1)',
                    color: isOwnerUser ? 'var(--color-gold)' : 'var(--color-ice)',
                    border: `1px solid ${isOwnerUser ? 'rgba(212,175,55,0.2)' : 'rgba(126,184,224,0.15)'}`,
                  }}
                >
                  {roleDef?.label || user.role}
                </span>

                {/* Status badge */}
                <span
                  className="px-2 py-1 rounded-md text-[10px]"
                  style={{
                    fontFamily: M,
                    fontWeight: 600,
                    background: user.status === 'active' ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
                    color: user.status === 'active' ? 'var(--color-status-green)' : 'var(--color-status-red)',
                    border: `1px solid ${user.status === 'active' ? 'rgba(16,185,129,0.15)' : 'rgba(239,68,68,0.15)'}`,
                  }}
                >
                  {user.status === 'active' ? 'Activo' : 'Inactivo'}
                </span>
              </div>

              {/* Actions */}
              {!isCurrentUser && (
                <div className="flex items-center gap-1.5 shrink-0">
                  <button
                    onClick={() => { setEditUser(user); setShowForm(true) }}
                    className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-text-secondary)] hover:text-white hover:bg-white/5 transition-colors"
                    title="Editar"
                  >
                    <Pencil className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => handleToggleStatus(user)}
                    className="p-2 rounded-lg bg-transparent border-none cursor-pointer transition-colors"
                    style={{
                      color: user.status === 'active' ? 'var(--color-status-yellow)' : 'var(--color-status-green)',
                    }}
                    title={user.status === 'active' ? 'Desactivar' : 'Activar'}
                  >
                    {user.status === 'active' ? <UserX className="w-4 h-4" /> : <UserCheck className="w-4 h-4" />}
                  </button>
                  {!isOwnerUser && (
                    <button
                      onClick={() => handleDelete(user)}
                      className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-status-red)] hover:bg-[var(--color-status-red)]/10 transition-colors"
                      title="Eliminar"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
              )}
            </div>
          )
        })}
      </div>

      {/* Create/Edit form overlay */}
      {showForm && (
        <UserFormModal
          user={editUser}
          assignableRoles={assignableRoles}
          onClose={() => { setShowForm(false); setEditUser(null) }}
          onSaved={loadUsers}
          currentUid={currentUid}
        />
      )}
    </div>
  )
}

// ============================================
// USER FORM MODAL
// ============================================

const UserFormModal = ({ user, assignableRoles, onClose, onSaved, currentUid }) => {
  const isEdit = !!user
  const [fullName, setFullName] = useState(user?.fullName || '')
  const [email, setEmail] = useState(user?.email || '')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [role, setRole] = useState(user?.role || 'employee')
  const [permissions, setPermissions] = useState(user?.permissions || [])
  const [useCustomPerms, setUseCustomPerms] = useState(
    Array.isArray(user?.permissions) && user.permissions.length > 0
  )
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setSaving(true)

    try {
      if (isEdit) {
        await updateUser(user.id, {
          fullName: fullName.trim(),
          role,
          permissions: useCustomPerms ? permissions : [],
        })
      } else {
        await createUser({
          email: email.trim(),
          password,
          fullName: fullName.trim(),
          role,
          permissions: useCustomPerms ? permissions : [],
          createdBy: currentUid,
        })
      }
      await onSaved()
      onClose()
    } catch (err) {
      setError(err.message)
    } finally {
      setSaving(false)
    }
  }

  const togglePerm = (key) => {
    setPermissions((prev) =>
      prev.includes(key) ? prev.filter((p) => p !== key) : [...prev, key]
    )
  }

  // Filter out owner from assignable roles for non-owner users
  const selectableRoles = assignableRoles.filter((r) => {
    if (r.key === 'owner' && !isEdit) return false
    if (r.key === 'owner' && isEdit && user?.role !== 'owner') return false
    return true
  })

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60" />
      <div
        className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto rounded-2xl p-6 space-y-5"
        style={{
          background: '#0B1021',
          border: '1px solid rgba(212,175,55,0.15)',
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between">
          <h3 className="text-white text-base" style={{ fontFamily: M, fontWeight: 700 }}>
            {isEdit ? 'Editar Usuario' : 'Nuevo Usuario'}
          </h3>
          <button onClick={onClose} className="p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)] hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {error && (
          <div
            className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs"
            style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
          >
            <AlertCircle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Full name */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Nombre completo *
            </label>
            <input
              type="text"
              required
              value={fullName}
              onChange={(e) => setFullName(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Email */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Correo electrónico *
            </label>
            <input
              type="email"
              required
              disabled={isEdit}
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none disabled:opacity-50"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Password — only on create */}
          {!isEdit && (
            <div>
              <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
                Contraseña *
              </label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  required
                  minLength={6}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-3 py-2 pr-10 rounded-lg text-sm text-white outline-none"
                  style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)]"
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>
              <p className="text-[var(--color-text-muted)] text-[10px] mt-1" style={{ fontFamily: M }}>
                El usuario deberá cambiar su contraseña en el primer inicio de sesión.
              </p>
            </div>
          )}

          {/* Role */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Rol *
            </label>
            <select
              value={role}
              onChange={(e) => setRole(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: '#1E2D5A', border: '1px solid rgba(255,255,255,0.1)', appearance: 'auto' }}
            >
              {selectableRoles.map((r) => (
                <option key={r.key} value={r.key}>
                  {r.label}
                </option>
              ))}
            </select>
          </div>

          {/* Custom permissions override */}
          {role !== 'owner' && (
            <div>
              <label className="flex items-center gap-2 cursor-pointer mb-3">
                <input
                  type="checkbox"
                  checked={useCustomPerms}
                  onChange={(e) => setUseCustomPerms(e.target.checked)}
                  className="accent-[var(--color-gold)]"
                />
                <span className="text-[var(--color-text-secondary)] text-xs" style={{ fontFamily: M, fontWeight: 500 }}>
                  Permisos personalizados (sobreescribe los del rol)
                </span>
              </label>

              {useCustomPerms && (
                <div className="grid grid-cols-2 gap-2">
                  {ALL_MODULE_KEYS.map((key) => (
                    <label
                      key={key}
                      className="flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-colors"
                      style={{
                        background: permissions.includes(key) ? 'rgba(212,175,55,0.08)' : 'rgba(255,255,255,0.03)',
                        border: `1px solid ${permissions.includes(key) ? 'rgba(212,175,55,0.2)' : 'rgba(255,255,255,0.06)'}`,
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={permissions.includes(key)}
                        onChange={() => togglePerm(key)}
                        className="accent-[var(--color-gold)]"
                      />
                      <span className="text-xs text-white" style={{ fontFamily: M, fontWeight: 500 }}>
                        {MODULES[key]?.label || key}
                      </span>
                    </label>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Submit */}
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 rounded-lg text-xs text-[var(--color-text-secondary)] transition-colors"
              style={{ fontFamily: M, fontWeight: 600, background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', cursor: 'pointer' }}
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold disabled:opacity-40"
              style={{ fontFamily: M, fontWeight: 600, cursor: saving ? 'wait' : 'pointer' }}
            >
              {saving && <Loader2 className="w-3.5 h-3.5 animate-spin" />}
              {isEdit ? 'Guardar Cambios' : 'Crear Usuario'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ============================================
// ROLES TAB
// ============================================

const RolesTab = ({ rolesMap, roles }) => {
  const [showForm, setShowForm] = useState(false)
  const [editRole, setEditRole] = useState(null)
  const [error, setError] = useState('')
  const [deleting, setDeleting] = useState(null)

  // All roles: owner (hardcoded) + Firestore roles
  const allRoles = useMemo(() => {
    return [OWNER_ROLE, ...roles]
  }, [roles])

  const handleDelete = async (role) => {
    if (!confirm(`¿Eliminar el rol "${role.label}"?`)) return
    setDeleting(role.key)
    try {
      await deleteRole(role.key)
      // roles state will update via the AuthContext snapshot listener
    } catch (err) {
      setError(err.message)
    } finally {
      setDeleting(null)
    }
  }

  return (
    <div className="space-y-4">
      {error && (
        <div
          className="flex items-center gap-2 px-4 py-3 rounded-lg text-xs"
          style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
        >
          <AlertCircle className="w-4 h-4 shrink-0" />
          {error}
          <button onClick={() => setError('')} className="ml-auto p-0 bg-transparent border-none text-inherit cursor-pointer">
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      )}

      {/* Add role button */}
      <div className="flex justify-end">
        <button
          onClick={() => { setEditRole(null); setShowForm(true) }}
          className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold"
          style={{ fontFamily: M, fontWeight: 600 }}
        >
          <Plus className="w-4 h-4" />
          Crear Rol
        </button>
      </div>

      {/* Roles list */}
      <div className="space-y-3">
        {allRoles.map((role) => {
          const isOwnerRole = role.key === 'owner'
          const isSystemRole = role.isSystem

          return (
            <div
              key={role.key}
              className="card-navy rounded-xl p-4 space-y-3"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <ShieldCheck
                    className="w-5 h-5 shrink-0"
                    style={{ color: isOwnerRole ? 'var(--color-gold)' : 'var(--color-ice)' }}
                  />
                  <div>
                    <p className="text-white text-sm" style={{ fontFamily: M, fontWeight: 700 }}>
                      {role.label}
                      {isSystemRole && (
                        <span
                          className="ml-2 px-1.5 py-0.5 rounded text-[9px]"
                          style={{
                            fontFamily: M,
                            fontWeight: 600,
                            background: 'rgba(168,85,247,0.1)',
                            color: '#a855f7',
                            border: '1px solid rgba(168,85,247,0.15)',
                          }}
                        >
                          SISTEMA
                        </span>
                      )}
                    </p>
                    <p className="text-[var(--color-text-muted)] text-xs" style={{ fontFamily: M }}>
                      {role.description || 'Sin descripción'}
                    </p>
                  </div>
                </div>

                {!isOwnerRole && (
                  <div className="flex items-center gap-1.5">
                    <button
                      onClick={() => { setEditRole(role); setShowForm(true) }}
                      className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-text-secondary)] hover:text-white hover:bg-white/5 transition-colors"
                      title="Editar"
                    >
                      <Pencil className="w-4 h-4" />
                    </button>
                    {!isSystemRole && (
                      <button
                        onClick={() => handleDelete(role)}
                        disabled={deleting === role.key}
                        className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-status-red)] hover:bg-[var(--color-status-red)]/10 transition-colors disabled:opacity-40"
                        title="Eliminar"
                      >
                        {deleting === role.key ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                      </button>
                    )}
                  </div>
                )}
              </div>

              {/* Permission badges */}
              <div className="flex flex-wrap gap-1.5">
                {isOwnerRole ? (
                  <span
                    className="px-2 py-0.5 rounded-md text-[10px]"
                    style={{
                      fontFamily: M,
                      fontWeight: 600,
                      background: 'rgba(212,175,55,0.08)',
                      color: 'var(--color-gold)',
                      border: '1px solid rgba(212,175,55,0.15)',
                    }}
                  >
                    Acceso completo
                  </span>
                ) : (
                  (role.permissions || []).map((perm) => (
                    <span
                      key={perm}
                      className="px-2 py-0.5 rounded-md text-[10px]"
                      style={{
                        fontFamily: M,
                        fontWeight: 500,
                        background: 'rgba(126,184,224,0.08)',
                        color: 'var(--color-ice)',
                        border: '1px solid rgba(126,184,224,0.1)',
                      }}
                    >
                      {MODULES[perm]?.label || perm}
                    </span>
                  ))
                )}
              </div>
            </div>
          )
        })}
      </div>

      {/* Create/Edit role form */}
      {showForm && (
        <RoleFormModal
          role={editRole}
          onClose={() => { setShowForm(false); setEditRole(null) }}
        />
      )}
    </div>
  )
}

// ============================================
// ROLE FORM MODAL
// ============================================

const RoleFormModal = ({ role, onClose }) => {
  const isEdit = !!role
  const [key, setKey] = useState(role?.key || '')
  const [label, setLabel] = useState(role?.label || '')
  const [description, setDescription] = useState(role?.description || '')
  const [permissions, setPermissions] = useState(role?.permissions || [])
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setSaving(true)

    try {
      if (isEdit) {
        await updateRole(role.key, {
          label: label.trim(),
          description: description.trim(),
          permissions,
        })
      } else {
        await createRole({
          key: key.trim().toLowerCase(),
          label: label.trim(),
          description: description.trim(),
          permissions,
        })
      }
      onClose()
    } catch (err) {
      setError(err.message)
    } finally {
      setSaving(false)
    }
  }

  const togglePerm = (moduleKey) => {
    setPermissions((prev) =>
      prev.includes(moduleKey) ? prev.filter((p) => p !== moduleKey) : [...prev, moduleKey]
    )
  }

  const toggleAll = () => {
    if (permissions.length === ALL_MODULE_KEYS.length) {
      setPermissions([])
    } else {
      setPermissions([...ALL_MODULE_KEYS])
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60" />
      <div
        className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto rounded-2xl p-6 space-y-5"
        style={{ background: '#0B1021', border: '1px solid rgba(212,175,55,0.15)' }}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between">
          <h3 className="text-white text-base" style={{ fontFamily: M, fontWeight: 700 }}>
            {isEdit ? 'Editar Rol' : 'Nuevo Rol'}
          </h3>
          <button onClick={onClose} className="p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)] hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {error && (
          <div
            className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs"
            style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
          >
            <AlertCircle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Key — only on create */}
          {!isEdit && (
            <div>
              <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
                Clave (identificador único) *
              </label>
              <input
                type="text"
                required
                pattern="^[a-z0-9_-]+$"
                value={key}
                onChange={(e) => setKey(e.target.value.toLowerCase())}
                placeholder="ej: supervisor"
                className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
                style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
              />
              <p className="text-[var(--color-text-muted)] text-[10px] mt-1" style={{ fontFamily: M }}>
                Solo letras minúsculas, números, guiones y guiones bajos.
              </p>
            </div>
          )}

          {/* Label */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Nombre del rol *
            </label>
            <input
              type="text"
              required
              value={label}
              onChange={(e) => setLabel(e.target.value)}
              placeholder="ej: Supervisor"
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Description */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Descripción
            </label>
            <input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Breve descripción del rol..."
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Permissions */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <label className="text-[var(--color-text-secondary)] text-xs" style={{ fontFamily: M, fontWeight: 500 }}>
                Permisos de módulo
              </label>
              <button
                type="button"
                onClick={toggleAll}
                className="text-[10px] px-2 py-0.5 rounded bg-transparent border-none cursor-pointer transition-colors"
                style={{
                  fontFamily: M,
                  fontWeight: 600,
                  color: 'var(--color-gold)',
                }}
              >
                {permissions.length === ALL_MODULE_KEYS.length ? 'Quitar todos' : 'Seleccionar todos'}
              </button>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {ALL_MODULE_KEYS.map((moduleKey) => (
                <label
                  key={moduleKey}
                  className="flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-colors"
                  style={{
                    background: permissions.includes(moduleKey) ? 'rgba(212,175,55,0.08)' : 'rgba(255,255,255,0.03)',
                    border: `1px solid ${permissions.includes(moduleKey) ? 'rgba(212,175,55,0.2)' : 'rgba(255,255,255,0.06)'}`,
                  }}
                >
                  <input
                    type="checkbox"
                    checked={permissions.includes(moduleKey)}
                    onChange={() => togglePerm(moduleKey)}
                    className="accent-[var(--color-gold)]"
                  />
                  <span className="text-xs text-white" style={{ fontFamily: M, fontWeight: 500 }}>
                    {MODULES[moduleKey]?.label || moduleKey}
                  </span>
                </label>
              ))}
            </div>
          </div>

          {/* Submit */}
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 rounded-lg text-xs text-[var(--color-text-secondary)] transition-colors"
              style={{ fontFamily: M, fontWeight: 600, background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', cursor: 'pointer' }}
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold disabled:opacity-40"
              style={{ fontFamily: M, fontWeight: 600, cursor: saving ? 'wait' : 'pointer' }}
            >
              {saving && <Loader2 className="w-3.5 h-3.5 animate-spin" />}
              {isEdit ? 'Guardar Cambios' : 'Crear Rol'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

export default Settings

toolUseResult.content:
import React, { useState, useEffect, useCallback, useMemo } from 'react'
import {
  Settings as SettingsIcon,
  User,
  Users,
  ShieldCheck,
  Plus,
  Pencil,
  Trash2,
  Check,
  X,
  Loader2,
  AlertCircle,
  Eye,
  EyeOff,
  Save,
  UserCheck,
  UserX,
} from 'lucide-react'
import { useAuth } from '../../contexts/AuthContext'
import {
  fetchAllUsers,
  createUser,
  updateUser,
  updateOwnProfile,
  deactivateUser,
  activateUser,
  deleteUserProfile,
} from '../../services/UserService'
import { createRole, updateRole, deleteRole } from '../../services/RoleService'
import { MODULES, ALL_MODULE_KEYS, OWNER_ROLE } from '../../constants/roles'

const M = 'Montserrat, sans-serif'

// ============================================
// MAIN PAGE
// ============================================

const Settings = () => {
  const { userProfile, isOwner, rolesMap, roles, refreshUserProfile } = useAuth()
  const [tab, setTab] = useState('perfil')

  const tabs = useMemo(() => {
    const base = [{ key: 'perfil', label: 'Mi Perfil', icon: User }]
    if (isOwner) {
      base.push({ key: 'usuarios', label: 'Usuarios', icon: Users })
      base.push({ key: 'permisos', label: 'Roles y Permisos', icon: ShieldCheck })
    }
    return base
  }, [isOwner])

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div
          className="w-10 h-10 rounded-xl flex items-center justify-center"
          style={{ background: 'linear-gradient(135deg, var(--color-gold-dark) 0%, var(--color-gold) 100%)' }}
        >
          <SettingsIcon className="w-5 h-5 text-[#0A1128]" strokeWidth={2} />
        </div>
        <div>
          <h2 className="text-white text-xl" style={{ fontFamily: M, fontWeight: 700 }}>
            Configuración
          </h2>
          <p className="text-[var(--color-text-muted)] text-[11px]" style={{ fontFamily: M, fontWeight: 400 }}>
            {isOwner ? 'Administra tu perfil, usuarios y permisos del sistema' : 'Administra tu perfil personal'}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div
        className="flex items-center gap-1 rounded-lg p-0.5"
        style={{ backgroundColor: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', width: 'fit-content' }}
      >
        {tabs.map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs transition-all"
            style={{
              fontFamily: M,
              fontWeight: tab === key ? 700 : 500,
              background: tab === key ? 'var(--color-gold)' : 'transparent',
              color: tab === key ? '#0A1128' : 'var(--color-text-secondary)',
              border: 'none',
              cursor: 'pointer',
            }}
          >
            <Icon className="w-3.5 h-3.5" />
            {label}
          </button>
        ))}
      </div>

      {/* Tab content */}
      {tab === 'perfil' && (
        <ProfileTab userProfile={userProfile} refreshUserProfile={refreshUserProfile} />
      )}
      {tab === 'usuarios' && isOwner && (
        <UsersTab rolesMap={rolesMap} roles={roles} currentUid={userProfile?.id} />
      )}
      {tab === 'permisos' && isOwner && (
        <RolesTab rolesMap={rolesMap} roles={roles} />
      )}
    </div>
  )
}

// ============================================
// PROFILE TAB
// ============================================

const ProfileTab = ({ userProfile, refreshUserProfile }) => {
  const [fullName, setFullName] = useState(userProfile?.fullName || '')
  const [saving, setSaving] = useState(false)
  const [saved, setSaved] = useState(false)

  useEffect(() => {
    if (userProfile?.fullName) setFullName(userProfile.fullName)
  }, [userProfile?.fullName])

  const handleSave = async () => {
    if (!fullName.trim() || fullName === userProfile?.fullName) return
    setSaving(true)
    try {
      await updateOwnProfile(userProfile.id, { fullName: fullName.trim() })
      await refreshUserProfile()
      setSaved(true)
      setTimeout(() => setSaved(false), 2000)
    } catch (err) {
      alert('Error: ' + err.message)
    } finally {
      setSaving(false)
    }
  }

  const roleLabel = userProfile?.role === 'owner' ? 'Propietario' : userProfile?.role || '—'

  return (
    <div className="card-navy rounded-2xl p-6 max-w-lg space-y-5">
      <h3 className="text-white text-sm" style={{ fontFamily: M, fontWeight: 700 }}>
        Información Personal
      </h3>

      {/* Email — read only */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Correo electrónico
        </label>
        <div
          className="px-3 py-2 rounded-lg text-sm text-[var(--color-text-muted)]"
          style={{ fontFamily: M, background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.06)' }}
        >
          {userProfile?.email || '—'}
        </div>
      </div>

      {/* Role — read only */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Rol
        </label>
        <div
          className="px-3 py-2 rounded-lg text-sm"
          style={{
            fontFamily: M,
            fontWeight: 600,
            background: 'rgba(212, 175, 55, 0.08)',
            border: '1px solid rgba(212, 175, 55, 0.15)',
            color: 'var(--color-gold)',
          }}
        >
          {roleLabel}
        </div>
      </div>

      {/* Full name — editable */}
      <div>
        <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
          Nombre completo
        </label>
        <input
          type="text"
          value={fullName}
          onChange={(e) => setFullName(e.target.value)}
          className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
          style={{
            fontFamily: M,
            background: 'rgba(255,255,255,0.06)',
            border: '1px solid rgba(255,255,255,0.1)',
          }}
        />
      </div>

      <button
        onClick={handleSave}
        disabled={saving || !fullName.trim() || fullName === userProfile?.fullName}
        className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs transition-all disabled:opacity-40"
        style={{
          fontFamily: M,
          fontWeight: 600,
          background: saved ? 'var(--color-status-green)' : 'var(--color-gold)',
          color: '#0A1128',
          border: 'none',
          cursor: saving ? 'wait' : 'pointer',
        }}
      >
        {saving ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : saved ? <Check className="w-3.5 h-3.5" /> : <Save className="w-3.5 h-3.5" />}
        {saving ? 'Guardando...' : saved ? 'Guardado' : 'Guardar Cambios'}
      </button>
    </div>
  )
}

// ============================================
// USERS TAB
// ============================================

const UsersTab = ({ rolesMap, roles, currentUid }) => {
  const [users, setUsers] = useState([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [editUser, setEditUser] = useState(null)
  const [error, setError] = useState('')

  const loadUsers = useCallback(async () => {
    try {
      const data = await fetchAllUsers()
      setUsers(data)
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => { loadUsers() }, [loadUsers])

  const handleToggleStatus = async (user) => {
    try {
      if (user.status === 'active') {
        await deactivateUser(user.id)
      } else {
        await activateUser(user.id)
      }
      await loadUsers()
    } catch (err) {
      setError(err.message)
    }
  }

  const handleDelete = async (user) => {
    if (!confirm(`¿Eliminar el perfil de ${user.fullName}? Esta acción no se puede deshacer.`)) return
    try {
      await deleteUserProfile(user.id)
      await loadUsers()
    } catch (err) {
      setError(err.message)
    }
  }

  // Available roles for assignment (exclude owner — owner is hardcoded)
  const assignableRoles = useMemo(() => {
    return [OWNER_ROLE, ...roles]
  }, [roles])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="w-6 h-6 text-[var(--color-gold)] animate-spin" />
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Error banner */}
      {error && (
        <div
          className="flex items-center gap-2 px-4 py-3 rounded-lg text-xs"
          style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
        >
          <AlertCircle className="w-4 h-4 shrink-0" />
          {error}
          <button onClick={() => setError('')} className="ml-auto p-0 bg-transparent border-none text-inherit cursor-pointer">
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      )}

      {/* Add user button */}
      <div className="flex justify-end">
        <button
          onClick={() => { setEditUser(null); setShowForm(true) }}
          className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold"
          style={{ fontFamily: M, fontWeight: 600 }}
        >
          <Plus className="w-4 h-4" />
          Agregar Usuario
        </button>
      </div>

      {/* Users list */}
      <div className="space-y-3">
        {users.map((user) => {
          const roleDef = rolesMap.get(user.role)
          const isCurrentUser = user.id === currentUid
          const isOwnerUser = user.role === 'owner'

          return (
            <div
              key={user.id}
              className="card-navy rounded-xl p-4 flex flex-col sm:flex-row sm:items-center gap-3"
            >
              {/* Avatar + info */}
              <div className="flex items-center gap-3 flex-1 min-w-0">
                <div
                  className="w-10 h-10 rounded-full flex items-center justify-center shrink-0 text-sm"
                  style={{
                    fontFamily: M,
                    fontWeight: 700,
                    background: user.status === 'inactive'
                      ? 'rgba(255,255,255,0.05)'
                      : isOwnerUser
                        ? 'rgba(212,175,55,0.15)'
                        : 'rgba(126,184,224,0.15)',
                    color: user.status === 'inactive'
                      ? 'var(--color-text-muted)'
                      : isOwnerUser
                        ? 'var(--color-gold)'
                        : 'var(--color-ice)',
                  }}
                >
                  {user.fullName?.charAt(0)?.toUpperCase() || '?'}
                </div>
                <div className="min-w-0">
                  <p className="text-white text-sm truncate" style={{ fontFamily: M, fontWeight: 600 }}>
                    {user.fullName}
                    {isCurrentUser && (
                      <span className="text-[var(--color-text-muted)] text-[10px] ml-2" style={{ fontWeight: 400 }}>(tú)</span>
                    )}
                  </p>
                  <p className="text-[var(--color-text-muted)] text-xs truncate" style={{ fontFamily: M }}>
                    {user.email}
                  </p>
                </div>
              </div>

              {/* Role badge */}
              <div className="flex items-center gap-2">
                <span
                  className="px-2.5 py-1 rounded-md text-[10px]"
                  style={{
                    fontFamily: M,
                    fontWeight: 700,
                    background: isOwnerUser ? 'rgba(212,175,55,0.12)' : 'rgba(126,184,224,0.1)',
                    color: isOwnerUser ? 'var(--color-gold)' : 'var(--color-ice)',
                    border: `1px solid ${isOwnerUser ? 'rgba(212,175,55,0.2)' : 'rgba(126,184,224,0.15)'}`,
                  }}
                >
                  {roleDef?.label || user.role}
                </span>

                {/* Status badge */}
                <span
                  className="px-2 py-1 rounded-md text-[10px]"
                  style={{
                    fontFamily: M,
                    fontWeight: 600,
                    background: user.status === 'active' ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
                    color: user.status === 'active' ? 'var(--color-status-green)' : 'var(--color-status-red)',
                    border: `1px solid ${user.status === 'active' ? 'rgba(16,185,129,0.15)' : 'rgba(239,68,68,0.15)'}`,
                  }}
                >
                  {user.status === 'active' ? 'Activo' : 'Inactivo'}
                </span>
              </div>

              {/* Actions */}
              {!isCurrentUser && (
                <div className="flex items-center gap-1.5 shrink-0">
                  <button
                    onClick={() => { setEditUser(user); setShowForm(true) }}
                    className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-text-secondary)] hover:text-white hover:bg-white/5 transition-colors"
                    title="Editar"
                  >
                    <Pencil className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => handleToggleStatus(user)}
                    className="p-2 rounded-lg bg-transparent border-none cursor-pointer transition-colors"
                    style={{
                      color: user.status === 'active' ? 'var(--color-status-yellow)' : 'var(--color-status-green)',
                    }}
                    title={user.status === 'active' ? 'Desactivar' : 'Activar'}
                  >
                    {user.status === 'active' ? <UserX className="w-4 h-4" /> : <UserCheck className="w-4 h-4" />}
                  </button>
                  {!isOwnerUser && (
                    <button
                      onClick={() => handleDelete(user)}
                      className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-status-red)] hover:bg-[var(--color-status-red)]/10 transition-colors"
                      title="Eliminar"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
              )}
            </div>
          )
        })}
      </div>

      {/* Create/Edit form overlay */}
      {showForm && (
        <UserFormModal
          user={editUser}
          assignableRoles={assignableRoles}
          onClose={() => { setShowForm(false); setEditUser(null) }}
          onSaved={loadUsers}
          currentUid={currentUid}
        />
      )}
    </div>
  )
}

// ============================================
// USER FORM MODAL
// ============================================

const UserFormModal = ({ user, assignableRoles, onClose, onSaved, currentUid }) => {
  const isEdit = !!user
  const [fullName, setFullName] = useState(user?.fullName || '')
  const [email, setEmail] = useState(user?.email || '')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [role, setRole] = useState(user?.role || 'employee')
  const [permissions, setPermissions] = useState(user?.permissions || [])
  const [useCustomPerms, setUseCustomPerms] = useState(
    Array.isArray(user?.permissions) && user.permissions.length > 0
  )
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setSaving(true)

    try {
      if (isEdit) {
        await updateUser(user.id, {
          fullName: fullName.trim(),
          role,
          permissions: useCustomPerms ? permissions : [],
        })
      } else {
        await createUser({
          email: email.trim(),
          password,
          fullName: fullName.trim(),
          role,
          permissions: useCustomPerms ? permissions : [],
          createdBy: currentUid,
        })
      }
      await onSaved()
      onClose()
    } catch (err) {
      setError(err.message)
    } finally {
      setSaving(false)
    }
  }

  const togglePerm = (key) => {
    setPermissions((prev) =>
      prev.includes(key) ? prev.filter((p) => p !== key) : [...prev, key]
    )
  }

  // Filter out owner from assignable roles for non-owner users
  const selectableRoles = assignableRoles.filter((r) => {
    if (r.key === 'owner' && !isEdit) return false
    if (r.key === 'owner' && isEdit && user?.role !== 'owner') return false
    return true
  })

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60" />
      <div
        className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto rounded-2xl p-6 space-y-5"
        style={{
          background: '#0B1021',
          border: '1px solid rgba(212,175,55,0.15)',
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between">
          <h3 className="text-white text-base" style={{ fontFamily: M, fontWeight: 700 }}>
            {isEdit ? 'Editar Usuario' : 'Nuevo Usuario'}
          </h3>
          <button onClick={onClose} className="p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)] hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {error && (
          <div
            className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs"
            style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
          >
            <AlertCircle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Full name */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Nombre completo *
            </label>
            <input
              type="text"
              required
              value={fullName}
              onChange={(e) => setFullName(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Email */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Correo electrónico *
            </label>
            <input
              type="email"
              required
              disabled={isEdit}
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none disabled:opacity-50"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Password — only on create */}
          {!isEdit && (
            <div>
              <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
                Contraseña *
              </label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  required
                  minLength={6}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-3 py-2 pr-10 rounded-lg text-sm text-white outline-none"
                  style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)]"
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>
              <p className="text-[var(--color-text-muted)] text-[10px] mt-1" style={{ fontFamily: M }}>
                El usuario deberá cambiar su contraseña en el primer inicio de sesión.
              </p>
            </div>
          )}

          {/* Role */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Rol *
            </label>
            <select
              value={role}
              onChange={(e) => setRole(e.target.value)}
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: '#1E2D5A', border: '1px solid rgba(255,255,255,0.1)', appearance: 'auto' }}
            >
              {selectableRoles.map((r) => (
                <option key={r.key} value={r.key}>
                  {r.label}
                </option>
              ))}
            </select>
          </div>

          {/* Custom permissions override */}
          {role !== 'owner' && (
            <div>
              <label className="flex items-center gap-2 cursor-pointer mb-3">
                <input
                  type="checkbox"
                  checked={useCustomPerms}
                  onChange={(e) => setUseCustomPerms(e.target.checked)}
                  className="accent-[var(--color-gold)]"
                />
                <span className="text-[var(--color-text-secondary)] text-xs" style={{ fontFamily: M, fontWeight: 500 }}>
                  Permisos personalizados (sobreescribe los del rol)
                </span>
              </label>

              {useCustomPerms && (
                <div className="grid grid-cols-2 gap-2">
                  {ALL_MODULE_KEYS.map((key) => (
                    <label
                      key={key}
                      className="flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-colors"
                      style={{
                        background: permissions.includes(key) ? 'rgba(212,175,55,0.08)' : 'rgba(255,255,255,0.03)',
                        border: `1px solid ${permissions.includes(key) ? 'rgba(212,175,55,0.2)' : 'rgba(255,255,255,0.06)'}`,
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={permissions.includes(key)}
                        onChange={() => togglePerm(key)}
                        className="accent-[var(--color-gold)]"
                      />
                      <span className="text-xs text-white" style={{ fontFamily: M, fontWeight: 500 }}>
                        {MODULES[key]?.label || key}
                      </span>
                    </label>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Submit */}
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 rounded-lg text-xs text-[var(--color-text-secondary)] transition-colors"
              style={{ fontFamily: M, fontWeight: 600, background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', cursor: 'pointer' }}
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold disabled:opacity-40"
              style={{ fontFamily: M, fontWeight: 600, cursor: saving ? 'wait' : 'pointer' }}
            >
              {saving && <Loader2 className="w-3.5 h-3.5 animate-spin" />}
              {isEdit ? 'Guardar Cambios' : 'Crear Usuario'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

// ============================================
// ROLES TAB
// ============================================

const RolesTab = ({ rolesMap, roles }) => {
  const [showForm, setShowForm] = useState(false)
  const [editRole, setEditRole] = useState(null)
  const [error, setError] = useState('')
  const [deleting, setDeleting] = useState(null)

  // All roles: owner (hardcoded) + Firestore roles
  const allRoles = useMemo(() => {
    return [OWNER_ROLE, ...roles]
  }, [roles])

  const handleDelete = async (role) => {
    if (!confirm(`¿Eliminar el rol "${role.label}"?`)) return
    setDeleting(role.key)
    try {
      await deleteRole(role.key)
      // roles state will update via the AuthContext snapshot listener
    } catch (err) {
      setError(err.message)
    } finally {
      setDeleting(null)
    }
  }

  return (
    <div className="space-y-4">
      {error && (
        <div
          className="flex items-center gap-2 px-4 py-3 rounded-lg text-xs"
          style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
        >
          <AlertCircle className="w-4 h-4 shrink-0" />
          {error}
          <button onClick={() => setError('')} className="ml-auto p-0 bg-transparent border-none text-inherit cursor-pointer">
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      )}

      {/* Add role button */}
      <div className="flex justify-end">
        <button
          onClick={() => { setEditRole(null); setShowForm(true) }}
          className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold"
          style={{ fontFamily: M, fontWeight: 600 }}
        >
          <Plus className="w-4 h-4" />
          Crear Rol
        </button>
      </div>

      {/* Roles list */}
      <div className="space-y-3">
        {allRoles.map((role) => {
          const isOwnerRole = role.key === 'owner'
          const isSystemRole = role.isSystem

          return (
            <div
              key={role.key}
              className="card-navy rounded-xl p-4 space-y-3"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <ShieldCheck
                    className="w-5 h-5 shrink-0"
                    style={{ color: isOwnerRole ? 'var(--color-gold)' : 'var(--color-ice)' }}
                  />
                  <div>
                    <p className="text-white text-sm" style={{ fontFamily: M, fontWeight: 700 }}>
                      {role.label}
                      {isSystemRole && (
                        <span
                          className="ml-2 px-1.5 py-0.5 rounded text-[9px]"
                          style={{
                            fontFamily: M,
                            fontWeight: 600,
                            background: 'rgba(168,85,247,0.1)',
                            color: '#a855f7',
                            border: '1px solid rgba(168,85,247,0.15)',
                          }}
                        >
                          SISTEMA
                        </span>
                      )}
                    </p>
                    <p className="text-[var(--color-text-muted)] text-xs" style={{ fontFamily: M }}>
                      {role.description || 'Sin descripción'}
                    </p>
                  </div>
                </div>

                {!isOwnerRole && (
                  <div className="flex items-center gap-1.5">
                    <button
                      onClick={() => { setEditRole(role); setShowForm(true) }}
                      className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-text-secondary)] hover:text-white hover:bg-white/5 transition-colors"
                      title="Editar"
                    >
                      <Pencil className="w-4 h-4" />
                    </button>
                    {!isSystemRole && (
                      <button
                        onClick={() => handleDelete(role)}
                        disabled={deleting === role.key}
                        className="p-2 rounded-lg bg-transparent border-none cursor-pointer text-[var(--color-status-red)] hover:bg-[var(--color-status-red)]/10 transition-colors disabled:opacity-40"
                        title="Eliminar"
                      >
                        {deleting === role.key ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                      </button>
                    )}
                  </div>
                )}
              </div>

              {/* Permission badges */}
              <div className="flex flex-wrap gap-1.5">
                {isOwnerRole ? (
                  <span
                    className="px-2 py-0.5 rounded-md text-[10px]"
                    style={{
                      fontFamily: M,
                      fontWeight: 600,
                      background: 'rgba(212,175,55,0.08)',
                      color: 'var(--color-gold)',
                      border: '1px solid rgba(212,175,55,0.15)',
                    }}
                  >
                    Acceso completo
                  </span>
                ) : (
                  (role.permissions || []).map((perm) => (
                    <span
                      key={perm}
                      className="px-2 py-0.5 rounded-md text-[10px]"
                      style={{
                        fontFamily: M,
                        fontWeight: 500,
                        background: 'rgba(126,184,224,0.08)',
                        color: 'var(--color-ice)',
                        border: '1px solid rgba(126,184,224,0.1)',
                      }}
                    >
                      {MODULES[perm]?.label || perm}
                    </span>
                  ))
                )}
              </div>
            </div>
          )
        })}
      </div>

      {/* Create/Edit role form */}
      {showForm && (
        <RoleFormModal
          role={editRole}
          onClose={() => { setShowForm(false); setEditRole(null) }}
        />
      )}
    </div>
  )
}

// ============================================
// ROLE FORM MODAL
// ============================================

const RoleFormModal = ({ role, onClose }) => {
  const isEdit = !!role
  const [key, setKey] = useState(role?.key || '')
  const [label, setLabel] = useState(role?.label || '')
  const [description, setDescription] = useState(role?.description || '')
  const [permissions, setPermissions] = useState(role?.permissions || [])
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setSaving(true)

    try {
      if (isEdit) {
        await updateRole(role.key, {
          label: label.trim(),
          description: description.trim(),
          permissions,
        })
      } else {
        await createRole({
          key: key.trim().toLowerCase(),
          label: label.trim(),
          description: description.trim(),
          permissions,
        })
      }
      onClose()
    } catch (err) {
      setError(err.message)
    } finally {
      setSaving(false)
    }
  }

  const togglePerm = (moduleKey) => {
    setPermissions((prev) =>
      prev.includes(moduleKey) ? prev.filter((p) => p !== moduleKey) : [...prev, moduleKey]
    )
  }

  const toggleAll = () => {
    if (permissions.length === ALL_MODULE_KEYS.length) {
      setPermissions([])
    } else {
      setPermissions([...ALL_MODULE_KEYS])
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60" />
      <div
        className="relative w-full max-w-lg max-h-[90vh] overflow-y-auto rounded-2xl p-6 space-y-5"
        style={{ background: '#0B1021', border: '1px solid rgba(212,175,55,0.15)' }}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between">
          <h3 className="text-white text-base" style={{ fontFamily: M, fontWeight: 700 }}>
            {isEdit ? 'Editar Rol' : 'Nuevo Rol'}
          </h3>
          <button onClick={onClose} className="p-1 bg-transparent border-none cursor-pointer text-[var(--color-text-muted)] hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {error && (
          <div
            className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs"
            style={{ fontFamily: M, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', color: '#f87171' }}
          >
            <AlertCircle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Key — only on create */}
          {!isEdit && (
            <div>
              <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
                Clave (identificador único) *
              </label>
              <input
                type="text"
                required
                pattern="^[a-z0-9_-]+$"
                value={key}
                onChange={(e) => setKey(e.target.value.toLowerCase())}
                placeholder="ej: supervisor"
                className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
                style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
              />
              <p className="text-[var(--color-text-muted)] text-[10px] mt-1" style={{ fontFamily: M }}>
                Solo letras minúsculas, números, guiones y guiones bajos.
              </p>
            </div>
          )}

          {/* Label */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Nombre del rol *
            </label>
            <input
              type="text"
              required
              value={label}
              onChange={(e) => setLabel(e.target.value)}
              placeholder="ej: Supervisor"
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Description */}
          <div>
            <label className="text-[var(--color-text-secondary)] text-xs mb-1 block" style={{ fontFamily: M, fontWeight: 500 }}>
              Descripción
            </label>
            <input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Breve descripción del rol..."
              className="w-full px-3 py-2 rounded-lg text-sm text-white outline-none"
              style={{ fontFamily: M, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)' }}
            />
          </div>

          {/* Permissions */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <label className="text-[var(--color-text-secondary)] text-xs" style={{ fontFamily: M, fontWeight: 500 }}>
                Permisos de módulo
              </label>
              <button
                type="button"
                onClick={toggleAll}
                className="text-[10px] px-2 py-0.5 rounded bg-transparent border-none cursor-pointer transition-colors"
                style={{
                  fontFamily: M,
                  fontWeight: 600,
                  color: 'var(--color-gold)',
                }}
              >
                {permissions.length === ALL_MODULE_KEYS.length ? 'Quitar todos' : 'Seleccionar todos'}
              </button>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {ALL_MODULE_KEYS.map((moduleKey) => (
                <label
                  key={moduleKey}
                  className="flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer transition-colors"
                  style={{
                    background: permissions.includes(moduleKey) ? 'rgba(212,175,55,0.08)' : 'rgba(255,255,255,0.03)',
                    border: `1px solid ${permissions.includes(moduleKey) ? 'rgba(212,175,55,0.2)' : 'rgba(255,255,255,0.06)'}`,
                  }}
                >
                  <input
                    type="checkbox"
                    checked={permissions.includes(moduleKey)}
                    onChange={() => togglePerm(moduleKey)}
                    className="accent-[var(--color-gold)]"
                  />
                  <span className="text-xs text-white" style={{ fontFamily: M, fontWeight: 500 }}>
                    {MODULES[moduleKey]?.label || moduleKey}
                  </span>
                </label>
              ))}
            </div>
          </div>

          {/* Submit */}
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 rounded-lg text-xs text-[var(--color-text-secondary)] transition-colors"
              style={{ fontFamily: M, fontWeight: 600, background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', cursor: 'pointer' }}
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={saving}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-xs btn-gold disabled:opacity-40"
              style={{ fontFamily: M, fontWeight: 600, cursor: saving ? 'wait' : 'pointer' }}
            >
              {saving && <Loader2 className="w-3.5 h-3.5 animate-spin" />}
              {isEdit ? 'Guardar Cambios' : 'Crear Rol'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

export default Settings

