import React, { Suspense, lazy } from 'react'
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom'
import { CartProvider } from './contexts/CartContext'
import { AuthProvider } from './contexts/AuthContext'
import { MainLayout } from './components/layout'
import { AdminLayout } from './components/admin'
import PrivateRoute from './components/PrivateRoute'
import { LoadingSpinner } from './components/ui'

// Retry dynamic imports — auto-reload on stale chunk after deploy
const lazyLoad = (importFn) =>
  lazy(() =>
    importFn().catch(() => {
      window.location.reload()
      return new Promise(() => {}) // never resolves — page is reloading
    })
  )

const Home = lazyLoad(() => import('./pages/Home'))
const Catalog = lazyLoad(() => import('./pages/Catalog'))
const Sell = lazyLoad(() => import('./pages/Sell'))
const Checkout = lazyLoad(() => import('./pages/Checkout'))
const ProductDetail = lazyLoad(() => import('./pages/ProductDetail'))
const Brokerage = lazyLoad(() => import('./pages/Brokerage'))

const AdminLogin = lazyLoad(() => import('./pages/admin/Login'))
const AdminDashboard = lazyLoad(() => import('./pages/admin/Dashboard'))
const AdminOrders = lazyLoad(() => import('./pages/admin/Orders'))
const AdminAcquisitions = lazyLoad(() => import('./pages/admin/Acquisitions'))
const AdminInventory = lazyLoad(() => import('./pages/admin/Inventory'))
const AdminBrokerageRequests = lazyLoad(() => import('./pages/admin/BrokerageRequests'))
const AdminClients = lazyLoad(() => import('./pages/admin/Clients'))
const AdminMarketing = lazyLoad(() => import('./pages/admin/Marketing'))
const AdminPersonalCollection = lazyLoad(() => import('./pages/admin/PersonalCollection'))
const AdminScoutingTool = lazyLoad(() => import('./pages/admin/ScoutingTool'))
const AdminBoxBreaks = lazyLoad(() => import('./pages/admin/BoxBreaks'))
const AdminGrading = lazyLoad(() => import('./pages/admin/Grading'))

function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <CartProvider>
          <Suspense fallback={<LoadingSpinner />}>
            <Routes>
              {/* ── Public storefront ── */}
              <Route element={<MainLayout />}>
                <Route path="/" element={<Home />} />
                <Route path="/comprar" element={<Catalog />} />
                <Route path="/vender" element={<Sell />} />
                <Route path="/carrito" element={<Checkout />} />
                <Route path="/producto/:id" element={<ProductDetail />} />
                <Route path="/encargos" element={<Brokerage />} />
              </Route>

              {/* ── Admin: public login ── */}
              <Route path="/admin/login" element={<AdminLogin />} />

              {/* ── Admin: protected routes ── */}
              <Route
                path="/admin"
                element={
                  <PrivateRoute>
                    <AdminLayout />
                  </PrivateRoute>
                }
              >
                <Route index element={<AdminDashboard />} />
                <Route path="ordenes" element={<AdminOrders />} />
                <Route path="adquisiciones" element={<AdminAcquisitions />} />
                <Route path="inventario" element={<AdminInventory />} />
                <Route path="encargos" element={<AdminBrokerageRequests />} />
                <Route path="clientes" element={<AdminClients />} />
                <Route path="marketing" element={<AdminMarketing />} />
                <Route path="coleccion" element={<AdminPersonalCollection />} />
                <Route path="scouting" element={<AdminScoutingTool />} />
                <Route path="aperturas" element={<AdminBoxBreaks />} />
                <Route path="grading" element={<AdminGrading />} />
              </Route>

              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </Suspense>
        </CartProvider>
      </AuthProvider>
    </BrowserRouter>
  )
}

export default App

