rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // ============================================
    // HELPERS
    // ============================================
    function isSignedIn() {
      return request.auth != null;
    }
    function isSelf(uid) {
      return request.auth != null && request.auth.uid == uid;
    }
    function getUserDoc() {
      return get(/databases/$(database)/documents/admin_users/$(request.auth.uid)).data;
    }
    function isOwner() {
      return isSignedIn()
        && exists(/databases/$(database)/documents/admin_users/$(request.auth.uid))
        && getUserDoc().role == 'owner'
        && getUserDoc().status == 'active';
    }
    function isAdminOrOwner() {
      return isSignedIn()
        && exists(/databases/$(database)/documents/admin_users/$(request.auth.uid))
        && getUserDoc().role in ['owner', 'admin']
        && getUserDoc().status == 'active';
    }
    function isActiveUser() {
      return isSignedIn()
        && exists(/databases/$(database)/documents/admin_users/$(request.auth.uid))
        && getUserDoc().status == 'active';
    }
    function noProfileYet() {
      return !exists(/databases/$(database)/documents/admin_users/$(request.auth.uid));
    }

    // Block all access by default
    match /{document=**} {
      allow read, write: if false;
    }

    // ============================================
    // ADMIN_USERS — profile docs with role + permissions
    // ============================================
    match /admin_users/{userId} {
      // Any signed-in user can read their own profile. Owner can read all.
      allow read: if isSelf(userId) || isOwner();

      // Bootstrap: first user creates their own doc as owner
      allow create: if isSelf(userId) && noProfileYet();

      // Owner can create any user doc (admin panel)
      allow create: if isOwner();

      // Owner can update any user. Users can update their own fullName only.
      allow update: if isOwner()
        || (isSelf(userId)
            && request.resource.data.role == resource.data.role
            && request.resource.data.permissions == resource.data.permissions
            && request.resource.data.status == resource.data.status);

      // Only owner can delete user docs
      allow delete: if isOwner();
    }

    // ============================================
    // ROLES — named permission bundles
    // ============================================
    match /roles/{roleId} {
      // Any authenticated user can read roles (needed to resolve own permissions)
      allow read: if isSignedIn();

      // Only owner can manage roles
      allow create, update, delete: if isOwner();
    }

    // ============================================
    // PRODUCTS — public read, active admin write
    // ============================================
    match /products/{productId} {
      allow read: if true;
      allow write: if isActiveUser();
    }

    // ============================================
    // ORDERS — public create (customers), active admin manage
    // ============================================
    match /orders/{orderId} {
      allow create: if true;
      allow read, update, delete: if isActiveUser();
    }

    // ============================================
    // BUY REQUESTS — public create, active admin manage
    // ============================================
    match /buy_requests/{requestId} {
      allow create: if true;
      allow read, update, delete: if isActiveUser();
    }

    // ============================================
    // BROKERAGE REQUESTS — public create, active admin manage
    // ============================================
    match /brokerage_requests/{requestId} {
      allow create: if true;
      allow read, update, delete: if isActiveUser();
    }

    // ============================================
    // MAIL CAMPAIGNS — active admin only
    // ============================================
    match /mail_campaigns/{campaignId} {
      allow read, write: if isActiveUser();
    }

    // ============================================
    // PERSONAL COLLECTION — public read, active admin write
    // ============================================
    match /personal_collection/{cardId} {
      allow read: if true;
      allow write: if isActiveUser();
    }

    // ============================================
    // SCOUTING LISTS — active admin only
    // ============================================
    match /scouting_lists/{listId} {
      allow read, write: if isActiveUser();
    }

    // ============================================
    // BOX BREAKS — active admin only
    // ============================================
    match /box_breaks/{breakId} {
      allow read, write: if isActiveUser();
    }

    // ============================================
    // GRADING SUBMISSIONS — active admin only
    // ============================================
    match /grading_submissions/{submissionId} {
      allow read, write: if isActiveUser();
    }

    // ============================================
    // SETTINGS — public read, owner write
    // ============================================
    match /Settings/{document=**} {
      allow read: if true;
      allow write: if isOwner();
    }
  }
}

